# write_readme.ps1 - run once from inside RAG-BANK:
#     powershell -ExecutionPolicy Bypass -File .\write_readme.ps1
$ErrorActionPreference = 'Stop'
$b = ''
[System.IO.File]::WriteAllBytes((Join-Path (Get-Location) 'README.md'), [System.Convert]::FromBase64String($b))
Write-Host 'wrote README.md' -ForegroundColor Green
